const CATEGORY_LABELS = {
  rate: "Mauvais résultat",
  bon: "Bon résultat",
  exact20: "Score exact",
  rare30: "Score rare",
  tresrare50: "Score très rare",
  megarare70: "Score méga rare",
  ultrarare100: "Score ultra rare",
};
const isExactTier = (key) =>
  ["exact20", "rare30", "tresrare50", "megarare70", "ultrarare100"].includes(key);

// Only renders something for exact-score points and x2 bonuses; everything
// else stays a bare line segment (no dot). Hidden entirely when the curve
// isn't focused, to keep the "no selection" state calm and uncluttered.
function Marker({ cx, cy, payload, playerKey, active }) {
  const detail = payload && payload[`${playerKey}_detail`];
  if (!detail || cx == null || cy == null) return null;
  if (!active) return null; // markers only shown once a curve is focused — keeps the default view calm
  const exact = isExactTier(detail.categoryKey);
  if (!exact && !detail.x2) return null;

  const r = 3;

  return (
    <g style={{ transition: "opacity 200ms ease" }}>
      {exact && !detail.x2 && <circle cx={cx} cy={cy} r={r} fill="#111111" />}
      {detail.x2 && !exact && <circle cx={cx} cy={cy} r={r} fill="#FFFFFF" />}
      {exact && detail.x2 && (
        <>
          <circle cx={cx - r} cy={cy} r={r} fill="#111111" stroke="rgba(0,0,0,0.4)" strokeWidth={0.5} />
          <circle cx={cx + r} cy={cy} r={r} fill="#FFFFFF" stroke="rgba(0,0,0,0.4)" strokeWidth={0.5} />
        </>
      )}
    </g>
  );
}

// Rich card following the touch/cursor: shows the focused players' rank,
// running total, delta since the previous match, and exact/x2 flags.
function ScrubberTooltip({ active, payload, label, focusPlayers, rankMap }) {
  if (!active || !payload || !payload.length) return null;
  const row = payload[0]?.payload;
  if (!row) return null;

  // Ranking AT this specific match date (not the final/current ranking).
  const rankAtRow = {};
  [...PLAYERS]
    .filter((p) => row[`${p.key}_cum`] != null)
    .sort((a, b) => row[`${b.key}_cum`] - row[`${a.key}_cum`])
    .forEach((p, i) => (rankAtRow[p.key] = i + 1));

  // Always show the focused players ordered by their overall (final) ranking,
  // best to worst — independent of the rank they had at this particular match.
  const players = (focusPlayers.length > 0 ? focusPlayers : PLAYERS.slice(0, 5))
    .slice()
    .sort((a, b) => rankMap[a.key] - rankMap[b.key]);

  return (
    <div
      className="rounded-lg border border-white/20 bg-[#0B3D2E]/95 backdrop-blur px-3 py-2 text-xs shadow-xl"
      style={{ pointerEvents: "none", minWidth: 180 }}
    >
      <div className="text-[10px] uppercase tracking-wide text-[#CFE3D8] mb-1">
        Match {row.matchNumber} · {row.label}
      </div>
      <div className="space-y-1">
        {players.map((p) => {
          const cum = row[`${p.key}_cum`];
          if (cum == null) return null;
          const d = row[`${p.key}_detail`];
          const delta = d?.points ?? 0;
          return (
            <div key={p.key} className="flex items-center justify-between gap-3">
              <span className="flex items-center gap-1.5 font-semibold" style={{ color: p.color }}>
                <span className="w-2 h-2 rounded-full" style={{ backgroundColor: p.color }} />
                {p.name}
                <span className="text-[#CFE3D8] font-normal">#{rankAtRow[p.key]}</span>
              </span>
              <span className="text-right">
                <span className="font-semibold">{cum}pts</span>{" "}
                <span className="text-[#CFE3D8]">
                  (+{delta}
                  {d?.x2 ? " ×2" : ""}
                  {d && isExactTier(d.categoryKey) ? " •exact" : ""})
                </span>
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}


